t.script:
(function () {
    var input = document.getElementById('repair_barcode_input');
    if (!input) return;
    input.focus();
    /* Los lectores HID envían los caracteres muy rápido y terminan con Enter.
       Al presionar Enter, enviamos el formulario inmediatamente. */
    input.addEventListener('keydown', function (e) {
        if (e.key === 'Enter') {
            e.preventDefault();
            document.getElementById('repair_scan_form').submit();
        }
    });
})();

(function () {
    var input = document.getElementById('batch_barcode_input');
    var form = document.getElementById('batch_add_form');
    if (!input || !form) return;
    input.focus();
    input.addEventListener('keydown', function (e) {
        if (e.key === 'Enter') {
            e.preventDefault();
            form.submit();
        }
    });
    var cameraBtn = document.getElementById('batch-scan-camera-btn');
    if (cameraBtn) {
        cameraBtn.addEventListener('click', function () {
            if (!window.RepairScanner) return;
            window.RepairScanner.open(function (value) {
                input.value = value;
                form.submit();
            });
        });
    }
})();

span.t-attf-class:
badge rounded-pill text-bg-#{
                        'success' if repair.state == 'done' else
                        'danger' if repair.state == 'cancel' else
                        'primary'}

div.script:
(function () {
    var input = document.getElementById('descarte_product_input');
    var hiddenId = document.getElementById('descarte_product_id');
    var dropdown = document.getElementById('descarte_product_dropdown');
    var submitBtn = document.getElementById('descarte_add_submit');
    var timer;
    document.body.appendChild(dropdown);
    dropdown.style.position = 'fixed';
    dropdown.style.zIndex = '9999';
    function positionDropdown() {
        var r = input.getBoundingClientRect();
        dropdown.style.top = r.bottom + 'px';
        dropdown.style.left = r.left + 'px';
        dropdown.style.width = r.width + 'px';
    }
    function showDropdown(products) {
        dropdown.innerHTML = '';
        if (!products.length) {
            var empty = document.createElement('div');
            empty.className = 'px-3 py-2 text-muted small';
            empty.textContent = 'Sin resultados';
            dropdown.appendChild(empty);
        } else {
            products.forEach(function (p) {
                var item = document.createElement('a');
                item.className = 'dropdown-item small py-2';
                item.href = '#';
                item.textContent = p.name + (p.uom ? ' (' + p.uom + ')' : '');
                item.addEventListener('click', function (e) {
                    e.preventDefault();
                    input.value = p.name;
                    hiddenId.value = p.id;
                    submitBtn.disabled = false;
                    dropdown.style.display = 'none';
                });
                dropdown.appendChild(item);
            });
        }
        positionDropdown();
        dropdown.style.display = 'block';
    }
    input.addEventListener('input', function () {
        hiddenId.value = '';
        submitBtn.disabled = true;
        clearTimeout(timer);
        var q = this.value.trim();
        if (q.length < 2) { dropdown.style.display = 'none'; return; }
        timer = setTimeout(function () {
            fetch('/my/repairs/products/search', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', id: 1, params: {query: q}}),
            }).then(function (r) { return r.json(); })
              .then(function (d) { showDropdown(d.result || []); })
              .catch(function () { dropdown.style.display = 'none'; });
        }, 300);
    });
    window.addEventListener('scroll', function () {
        if (dropdown.style.display !== 'none') positionDropdown();
    }, { passive: true });
    document.addEventListener('click', function (e) {
        if (e.target !== input && !dropdown.contains(e.target)) {
            dropdown.style.display = 'none';
        }
    });
})();

t.script:
(function () {
    var input = document.getElementById('part_product_input');
    var hiddenId = document.getElementById('part_product_id');
    var dropdown = document.getElementById('product_dropdown');
    var submitBtn = document.getElementById('add_part_submit');
    var timer;

    /* Mover el dropdown al body para escapar cualquier
       overflow:hidden de los contenedores padre. */
    document.body.appendChild(dropdown);
    dropdown.style.position = 'fixed';
    dropdown.style.zIndex = '9999';

    function positionDropdown() {
        var r = input.getBoundingClientRect();
        dropdown.style.top = r.bottom + 'px';
        dropdown.style.left = r.left + 'px';
        dropdown.style.width = r.width + 'px';
    }

    function showDropdown(products) {
        dropdown.innerHTML = '';
        if (!products.length) {
            var empty = document.createElement('div');
            empty.className = 'px-3 py-2 text-muted small';
            empty.textContent = 'Sin resultados';
            dropdown.appendChild(empty);
        } else {
            products.forEach(function (p) {
                var item = document.createElement('a');
                item.className = 'dropdown-item small py-2';
                item.href = '#';
                item.textContent = p.name + (p.uom ? ' (' + p.uom + ')' : '');
                item.addEventListener('click', function (e) {
                    e.preventDefault();
                    input.value = p.name;
                    hiddenId.value = p.id;
                    submitBtn.disabled = false;
                    dropdown.style.display = 'none';
                });
                dropdown.appendChild(item);
            });
        }
        positionDropdown();
        dropdown.style.display = 'block';
    }

    input.addEventListener('input', function () {
        hiddenId.value = '';
        submitBtn.disabled = true;
        clearTimeout(timer);
        var q = this.value.trim();
        if (q.length < 2) { dropdown.style.display = 'none'; return; }
        timer = setTimeout(function () {
            fetch('/my/repairs/products/search', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({jsonrpc: '2.0', method: 'call', id: 1, params: {query: q}}),
            }).then(function (r) { return r.json(); })
              .then(function (d) { showDropdown(d.result || []); })
              .catch(function () { dropdown.style.display = 'none'; });
        }, 300);
    });

    window.addEventListener('scroll', function () {
        if (dropdown.style.display !== 'none') positionDropdown();
    }, { passive: true });

    document.addEventListener('click', function (e) {
        if (e.target !== input && !dropdown.contains(e.target)) {
            dropdown.style.display = 'none';
        }
    });
})();
